'use client';

import React, { useState, useEffect } from 'react';

interface Company {
  id: string;
  name: string;
  logo_url?: string;
}

export function CompanyLogos() {
  const [companies, setCompanies] = useState<Company[]>([]);

  useEffect(() => {
    const fetchCompanies = async () => {
      try {
        const res = await fetch('http://localhost:8000/api/v1/simulation/state');
        const data = await res.json();
        setCompanies(data.companies.slice(0, 20));
      } catch (e) {
        console.error("Failed to fetch companies for logos", e);
      }
    };
    fetchCompanies();
  }, []);

  return (
    <div className="grid grid-cols-4 gap-4 p-4 bg-white/5 border border-white/10 rounded-xl">
      {companies.map(company => (
        <div key={company.id} className="flex flex-col items-center justify-center p-4 bg-slate-900 border border-white/5 rounded-lg hover:border-emerald-500/50 transition-colors group">
          <div className="w-12 h-12 bg-emerald-500/10 rounded-full flex items-center justify-center mb-2 group-hover:scale-110 transition-transform">
            <span className="text-emerald-400 font-bold text-lg">{company.name[0]}</span>
          </div>
          <span className="text-[10px] text-white/60 text-center truncate w-full">{company.name}</span>
        </div>
      ))}
      {companies.length === 0 && (
        <div className="col-span-4 py-12 text-center text-white/20 text-sm italic">
          Fetching top companies from Specter DB...
        </div>
      )}
    </div>
  );
}
