'use client';

import React, { useState, useEffect } from 'react';
import { Badge } from '@/components/ui/badge';
import { Building2, Users, TrendingUp, Wallet } from 'lucide-react';

interface Company {
  id: string;
  name: string;
  valuation: number;
  cash_on_hand: number;
  founder_ids: string[];
  employee_ids: string[];
  investor_ids: string[];
}

interface Person {
  id: string;
  name: string;
  role: string;
  company_id: string | null;
}

interface SimulationState {
  tick: number;
  companies: Company[];
  people: Person[];
}

export function VCSimDashboard() {
  const [state, setState] = useState<SimulationState | null>(null);

  useEffect(() => {
    const fetchState = async () => {
      try {
        const res = await fetch('http://localhost:8000/api/v1/simulation/state');
        if (!res.ok) throw new Error(`HTTP error! status: ${res.status}`);
        const data = await res.json();
        setState(data);
      } catch (e) {
        console.error("Failed to fetch sim state", e);
      }
    };

    fetchState();
    const interval = setInterval(fetchState, 5000);
    return () => clearInterval(interval);
  }, []);

  if (!state) return null;

  const investors = state.people.filter(p => p.role === 'investor');

  return (
    <div className="p-6 space-y-8 bg-slate-950/40 backdrop-blur-md border-l border-white/5 h-full overflow-y-auto w-96">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-light tracking-tighter text-white/90 uppercase">Market Preview</h2>
        <Badge variant="outline" className="text-[10px] font-mono border-emerald-500/30 text-emerald-400 bg-emerald-500/5">
          TICK {state.tick}
        </Badge>
      </div>

      {/* Companies Visual Grid */}
      <div className="space-y-4">
        <h3 className="text-[10px] font-bold text-white/30 uppercase tracking-[0.2em] flex items-center gap-2">
          <Building2 className="w-3 h-3" /> Active Portfolio ({state.companies.length})
        </h3>
        <div className="grid grid-cols-2 gap-3">
          {state.companies.map(company => (
            <div 
              key={company.id} 
              className="relative group p-4 bg-gradient-to-br from-white/5 to-transparent border border-white/10 rounded-xl hover:border-emerald-500/40 transition-all duration-300 cursor-pointer overflow-hidden"
            >
              {/* Isometric "Building" decoration */}
              <div className="absolute -right-2 -bottom-2 opacity-10 group-hover:opacity-20 transition-opacity">
                <Building2 className="w-16 h-16 text-emerald-400" />
              </div>
              
              <div className="relative z-10 space-y-3">
                <div className="w-10 h-10 bg-emerald-500/10 rounded-lg flex items-center justify-center border border-emerald-500/20 group-hover:scale-110 transition-transform">
                  <span className="text-emerald-400 font-bold text-lg">{company.name[0]}</span>
                </div>
                <div>
                  <div className="text-xs font-semibold text-white truncate">{company.name}</div>
                  <div className="flex items-center gap-1 mt-1">
                    <TrendingUp className="w-2 h-2 text-emerald-400" />
                    <span className="text-[10px] text-white/50 font-mono">
                      ${(company.valuation / 1000000).toFixed(1)}M
                    </span>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Investors Visual Grid */}
      <div className="space-y-4">
        <h3 className="text-[10px] font-bold text-white/30 uppercase tracking-[0.2em] flex items-center gap-2">
          <Users className="w-3 h-3" /> Top Investors ({investors.length})
        </h3>
        <div className="flex flex-wrap gap-3">
          {investors.map(investor => (
            <div 
              key={investor.id} 
              className="flex flex-col items-center gap-2 group"
              title={investor.name}
            >
              <div className="w-12 h-12 rounded-full bg-slate-900 border border-white/10 flex items-center justify-center group-hover:border-blue-500/50 transition-all relative">
                <span className="text-blue-400 font-bold text-sm">{investor.name[0]}</span>
                <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-blue-500/20 border border-blue-500/40 rounded-full flex items-center justify-center">
                  <Wallet className="w-2 h-2 text-blue-400" />
                </div>
              </div>
              <span className="text-[9px] text-white/40 truncate w-12 text-center">{investor.name.split(' ')[0]}</span>
            </div>
          ))}
          {investors.length === 0 && (
            <div className="text-[10px] text-white/20 italic py-4">No active investors in pool...</div>
          )}
        </div>
      </div>

      {/* Talent Pulse */}
      <div className="space-y-4 pt-4 border-t border-white/5">
        <h3 className="text-[10px] font-bold text-white/30 uppercase tracking-[0.2em]">Talent Pulse</h3>
        <div className="space-y-2">
          {state.people.filter(p => p.role === 'employee').slice(-3).map(person => (
            <div key={person.id} className="flex items-center justify-between p-2 bg-white/5 border border-white/5 rounded-lg">
              <div className="flex items-center gap-2">
                <div className="w-6 h-6 rounded bg-emerald-500/10 flex items-center justify-center">
                  <span className="text-[10px] text-emerald-400 font-bold">{person.name[0]}</span>
                </div>
                <span className="text-[10px] text-white/70">{person.name}</span>
              </div>
              <Badge variant="outline" className="text-[8px] h-4 border-emerald-500/20 text-emerald-400 uppercase tracking-tighter">HIRED</Badge>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
